INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('bc0b9c8f-cefa-45b9-9614-a98e95b3e903', '9947b0a5-8aac-4146-8e55-3be06afb1a0e', 'overseas', 'parents', '시니어 친목회 베트남 다낭 힐링 여행, 이동이 너무 편했습니다', '걷는 일정을 최소화하고 마사지와 맛집 위주로 구성되어 시니어 회원들이 매우 만족하셨습니다.', '전용 대형 버스가 이동 때마다 바로 앞에 대기하고 있어 어르신들이 무더위에 고생하지 않으셨습니다. 가이드가 한국어에 능숙하고 유머러스하여 이동 중에도 지루할 틈이 없었습니다. 숙소 내 조식 퀄리티가 훌륭하여 어르신들이 아침 식사를 매번 챙겨 드실 정도로 만족하셨습니다.', '시니어모임', '베트남', '다낭', ARRAY(SELECT json_array_elements_text('["시니어모임","힐링여행","이동편안"]'::json)), '2025-01-19T15:00:00.000Z'::timestamp with time zone, '2025-01-26T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 47, 'published', NULL, 'manual_admin', '2025-01-27T10:30:00.000Z'::timestamp with time zone, NULL, '2025-01-27T10:45:00.000Z'::timestamp with time zone, '2025-01-27T09:30:00.000Z'::timestamp with time zone, '2025-01-27T10:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('7426dc8a-2283-4d0e-9238-2b0d53dd93ba', 'a03f62da-7acf-4cdf-b18a-f366cebdf1f6', 'overseas', 'group_friends', '부부동반 모임 방콕/파타야 여행, 여유로운 휴식과 미식이 가득했습니다', '부부들이 선호하는 마사지 투어와 루프탑 디너 일정이 완벽하게 배치되었습니다.', '파타야의 프라이빗한 풀빌라 숙소 덕분에 부부들만의 오붓한 시간을 가질 수 있었습니다. 가이드가 추천해준 태국 전통 요리들이 향신료가 강하지 않아 모두가 맛있게 식사했습니다. 단체 이동 중에도 개별 쇼핑 시간을 충분히 할당해주어 만족도가 높았습니다.', '부부동반모임', '태국', '방콕', ARRAY(SELECT json_array_elements_text('["부부동반모임","휴양여행","식사만족"]'::json)), '2025-02-13T15:00:00.000Z'::timestamp with time zone, '2025-02-19T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 12, 'published', NULL, 'manual_admin', '2025-02-20T10:00:00.000Z'::timestamp with time zone, NULL, '2025-02-20T10:10:00.000Z'::timestamp with time zone, '2025-02-20T09:00:00.000Z'::timestamp with time zone, '2025-02-20T10:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('2aeba2e4-50b5-4d8a-8195-e37c20a36896', '6090caae-9404-4cf9-b0eb-ab41b317fb6b', 'overseas', 'group_corporate', '상인회 회원들과 함께한 베트남 다낭 연수, 단체 진행이 매우 원활했습니다', '30명 규모의 상인회 단체 여행에서 가장 중요한 식당 예약과 차량 배차가 완벽했습니다.', '대인원을 수용할 수 있는 현지 식당들이 미리 섭외되어 대기 시간 없이 식사가 가능했습니다. 연수 목적에 맞는 시장 방문과 자유시간이 적절히 섞여 회원들의 참여도가 높았습니다. 가이드의 유연한 대처로 돌발 상황 없이 일정을 마무리했습니다.', '상인회', '베트남', '다낭', ARRAY(SELECT json_array_elements_text('["상인회","단체연수","30명여행"]'::json)), '2025-03-09T15:00:00.000Z'::timestamp with time zone, '2025-03-14T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 3, 'published', NULL, 'manual_admin', '2025-03-15T11:00:00.000Z'::timestamp with time zone, NULL, '2025-03-15T11:20:00.000Z'::timestamp with time zone, '2025-03-15T10:00:00.000Z'::timestamp with time zone, '2025-03-15T11:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('a5261baa-b46d-4a8f-a5ea-e877c3e72589', '659b2d59-e95a-4dd6-b42e-228ae0be2439', 'domestic', 'group_small', '원우회 전주 한옥 마을 체험 여행, 전통의 멋을 느낀 시간이었습니다', '원우 12명과 함께 전주의 고즈넉한 한옥에서 보낸 하룻밤은 특별한 경험이었습니다.', '전통 한옥 숙소였지만 현대적인 편의시설이 잘 갖춰져 있어 불편함이 전혀 없었습니다. 현지 가이드가 추천해준 비빔밥과 막걸리 골목 탐방은 원우들 간의 우애를 다지기에 더할 나위 없었습니다. 이동 시 15인승 밴을 이용해 좁은 골목까지 편리하게 이동한 점이 좋았습니다.', '원우회', '한국', '전주', ARRAY(SELECT json_array_elements_text('["원우회","문화체험","12명여행"]'::json)), '2025-03-21T15:00:00.000Z'::timestamp with time zone, '2025-03-23T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 26, 'published', NULL, 'manual_admin', '2025-03-24T14:00:00.000Z'::timestamp with time zone, NULL, '2025-03-24T14:10:00.000Z'::timestamp with time zone, '2025-03-24T13:00:00.000Z'::timestamp with time zone, '2025-03-24T14:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('d4a73247-c8e4-453f-9d73-60d71138f6cc', '6b76aaf6-6f00-4ad6-a2fd-af4601c3b418', 'domestic', 'hiking', '산악회 정기 원정 제주 한라산 트레킹, 안전하고 즐거웠습니다', '등산 코스 선정부터 하산 후 뒤풀이 장소까지 모든 동선이 완벽했습니다.', '한라산 등반 허가 신청부터 차량 대기까지 꼼꼼하게 챙겨주셔서 회원들이 산행에만 집중할 수 있었습니다. 하산 시간에 맞춰 준비된 따뜻한 전골 요리는 회원들의 피로를 말끔히 씻어주었습니다. 40명의 대인원을 질서 있게 이끌어준 전문 산악 가이드의 노련함이 돋보였습니다.', '산악회', '한국', '제주', ARRAY(SELECT json_array_elements_text('["산악회","한라산트레킹","40명여행"]'::json)), '2025-04-19T15:00:00.000Z'::timestamp with time zone, '2025-04-22T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 20, 'published', NULL, 'manual_admin', '2025-04-23T10:00:00.000Z'::timestamp with time zone, NULL, '2025-04-23T10:15:00.000Z'::timestamp with time zone, '2025-04-23T09:00:00.000Z'::timestamp with time zone, '2025-04-23T10:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('cd8749a5-eaf9-485a-bb83-58235dafaa2f', '92286095-e671-412d-95d7-b9854dacb71d', 'domestic', 'group_friends', '대학원 동문 모임 제주 여행, 쾌적한 이동과 맛집 탐방이 즐거웠습니다', '동문 15명과 함께한 제주 여행은 렌터카 대신 전용 버스를 이용해 훨씬 편리했습니다.', '동문들끼리 술잔을 기울일 수 있도록 전용 차량을 지원받아 이동 시 걱정이 없었습니다. 현지인들이 찾는 진짜 맛집들로만 구성된 식사 코스 덕분에 입이 즐거운 여행이었습니다. 숙소 앞 바다 산책로와 여유로운 조식 시간까지 모두 완벽한 배려였습니다.', '대학원동문모임', '한국', '제주', ARRAY(SELECT json_array_elements_text('["대학원동문모임","친목여행","15명여행"]'::json)), '2025-04-21T15:00:00.000Z'::timestamp with time zone, '2025-04-24T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, true, 4, 'published', NULL, 'manual_admin', '2025-04-25T09:00:00.000Z'::timestamp with time zone, NULL, '2025-04-25T09:15:00.000Z'::timestamp with time zone, '2025-04-25T08:30:00.000Z'::timestamp with time zone, '2025-04-25T09:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('43e4254f-0138-4f4c-ade4-8509e342de96', '5e548744-b971-4400-b0d5-8d6d29bcdd3a', 'domestic', 'parents', '시니어 친목회 제주 억새 여행, 가을의 낭만을 가득 느끼고 왔습니다', '어르신 20명과 함께한 가을 제주 여행은 무리한 산행 대신 완만한 산책로 위주로 구성되어 좋았습니다.', '억새가 만발한 산책로를 가이드와 함께 천천히 걸으며 사진도 찍고 담소를 나눈 시간이 매우 여유로웠습니다. 매일 제공된 전복죽과 갈치조림 등 제주 보양식은 어르신들의 기력을 챙기기에 충분했습니다. 차량 내부에 항상 준비된 따뜻한 차와 간식 서비스가 시니어 회원들에게 호평을 받았습니다.', '시니어모임', '한국', '제주', ARRAY(SELECT json_array_elements_text('["시니어모임","가을여행","20명여행"]'::json)), '2025-04-28T15:00:00.000Z'::timestamp with time zone, '2025-05-01T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 38, 'published', NULL, 'manual_admin', '2025-05-02T09:30:00.000Z'::timestamp with time zone, NULL, '2025-05-02T09:40:00.000Z'::timestamp with time zone, '2025-05-02T08:00:00.000Z'::timestamp with time zone, '2025-05-02T09:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('9b1deb4d-3b7d-4bad-9bdd-2b0d7b3dcb6d', 'a1b2c3d4-e5f6-4a5b-8c9d-0e1f2a3b4c5d', 'overseas', 'group_corporate', '최고경영자 모임으로 다녀온 큐슈 여행, 동선과 식사 만족도가 높았습니다', '20명의 인원이 이동하기에 최적화된 동선과 품격 있는 식사가 인상적이었습니다.', '대표님들이 모이는 자리라 식사와 숙소의 품격에 신경을 많이 썼는데 기대 이상이었습니다. 대형 버스 이동 중에도 가이드의 노련한 진행 덕분에 원우들 간의 대화 시간이 충분히 보장되었습니다. 전 일정 동안 불편함 없이 매끄럽게 운영된 점에 감사드립니다.', '최고경영자모임', '일본', '큐슈', ARRAY(SELECT json_array_elements_text('["최고경영자모임","친목여행","20명여행"]'::json)), '2025-05-11T15:00:00.000Z'::timestamp with time zone, '2025-05-14T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, true, 0, 'published', NULL, 'manual_admin', '2025-05-15T10:00:00.000Z'::timestamp with time zone, NULL, '2025-05-15T10:05:00.000Z'::timestamp with time zone, '2025-05-15T09:30:00.000Z'::timestamp with time zone, '2025-05-15T10:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('cf115c24-886e-4c0d-a767-a76d697e06cc', 'ac1e3e07-1050-4618-83c7-1ece8191dabc', 'domestic', 'group_small', '소규모 단체 여수 밤바다 우정 여행, 10명이 즐기기에 딱이었습니다', '10인승 밴을 이용해 여수 골목골목의 맛집들을 편리하게 방문했습니다.', '대형 버스가 가기 힘든 여수 시내의 숨은 명소들을 가이드의 안내로 편하게 구경했습니다. 오션뷰 풀빌라 숙소에서의 하룻밤은 친구들 모두가 만족해하는 선택이었습니다. 케이블카와 향일암 동선이 겹치지 않게 잘 조율되어 피로감 없이 즐겼습니다.', '소규모단체', '한국', '여수', ARRAY(SELECT json_array_elements_text('["소규모단체","우정여행","10명여행"]'::json)), '2025-05-24T15:00:00.000Z'::timestamp with time zone, '2025-05-27T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 18, 'published', NULL, 'manual_admin', '2025-05-28T09:00:00.000Z'::timestamp with time zone, NULL, '2025-05-28T09:10:00.000Z'::timestamp with time zone, '2025-05-28T08:30:00.000Z'::timestamp with time zone, '2025-05-28T09:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('02f86db4-46ee-4c08-ba53-7631c54f8311', '066e4302-c632-4f68-9bc0-e164f2bfdbbb', 'overseas', 'group_friends', '동문회 이탈리아 로마 역사 탐방, 동문들 간의 우애를 다졌습니다', '로마의 유적지를 30명의 동문이 전문 가이드와 함께 심도 있게 탐방한 유익한 시간이었습니다.', '단체 관광임에도 불구하고 개별 수신기를 지급받아 가이드의 설명을 놓치지 않고 들을 수 있었습니다. 저녁마다 로마 시내의 운치 있는 레스토랑에서 즐긴 정찬은 동문들 간의 대화를 더욱 풍성하게 했습니다. 숙소가 주요 관광지 근처에 위치해 있어 이른 아침이나 늦은 저녁 산책하기에 너무 좋았습니다.', '동문회', '이탈리아', '로마', ARRAY(SELECT json_array_elements_text('["동문회","역사탐방","30명여행"]'::json)), '2025-05-29T15:00:00.000Z'::timestamp with time zone, '2025-06-09T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 33, 'published', NULL, 'manual_admin', '2025-06-10T15:00:00.000Z'::timestamp with time zone, NULL, '2025-06-10T15:20:00.000Z'::timestamp with time zone, '2025-06-10T14:00:00.000Z'::timestamp with time zone, '2025-06-10T15:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('f01f3bba-356d-49a5-889c-e864a099203c', '3d6fab87-885e-4f27-ad0d-329cc3966608', 'overseas', 'group_corporate', '상인회 회원 베트남 호치민 경제 시찰, 많은 영감을 얻었습니다', '호치민의 활기찬 시장 경제를 직접 보고 느끼며 회원들 간의 사업 아이디어를 공유했습니다.', '대형 유통 매장과 전통 시장의 대비를 통해 유통 흐름을 파악하는 유익한 시간이었습니다. 인솔자가 현지 비즈니스 관습까지 설명해주어 단순 관광 이상의 깊이 있는 연수가 되었습니다. 이동 중 제공된 한식 도시락과 현지 특식의 조화가 훌륭하여 식사 만족도가 높았습니다.', '상인회', '베트남', '호치민', ARRAY(SELECT json_array_elements_text('["상인회","경제시찰","30명여행"]'::json)), '2025-06-04T15:00:00.000Z'::timestamp with time zone, '2025-06-11T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 24, 'published', NULL, 'manual_admin', '2025-06-12T16:00:00.000Z'::timestamp with time zone, NULL, '2025-06-12T16:20:00.000Z'::timestamp with time zone, '2025-06-12T15:00:00.000Z'::timestamp with time zone, '2025-06-12T16:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('7c2e9f5a-1d8c-4b9a-8e2f-3a4b5c6d7e8f', '48bd2a63-fe6e-42c4-a833-3b67c38590d7', 'overseas', 'hiking', '산악회 일정으로 떠난 스위스, 자연경관과 일정 구성이 모두 좋았습니다', '회원들의 연령대를 고려한 완만한 트레킹 코스와 안전한 이동이 돋보였습니다.', '40여 명의 대규모 인원이었지만 전문 인솔자의 통제하에 안전하게 일정을 마쳤습니다. 스위스 알프스의 풍경을 즐기기에 무리 없는 트레킹 코스 배분이 훌륭했습니다. 숙소 컨디션과 한국인을 배려한 식단 구성도 만족스러웠습니다.', '산악회', '스위스', '인터라켄', ARRAY(SELECT json_array_elements_text('["산악회","자연경관","일정안정"]'::json)), '2025-06-19T15:00:00.000Z'::timestamp with time zone, '2025-06-24T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 1, 'published', NULL, 'manual_admin', '2025-06-25T14:00:00.000Z'::timestamp with time zone, NULL, '2025-06-25T14:10:00.000Z'::timestamp with time zone, '2025-06-25T11:00:00.000Z'::timestamp with time zone, '2025-06-25T14:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('8c9bf5fb-5342-4418-b2e5-251900da18fb', '5af7b8b3-ffff-4767-ac65-aafb589f3ee5', 'overseas', 'group_corporate', '최고경영자 모임 대만 타이베이 투어, 품격과 재미를 모두 잡았습니다', '대표님 15분과 함께한 타이베이 여행은 정갈한 식사와 세심한 가이드 서비스가 압권이었습니다.', '타이베이 101 빌딩의 전망대 관람과 전용 룸에서 즐긴 딤섬 만찬은 참석하신 모든 분들께 좋은 평가를 받았습니다. 단체 이동임에도 불구하고 각 대표님의 개별 요구사항을 가이드가 놓치지 않고 챙겨주었습니다. 숙소로 선정된 5성급 호텔의 위치와 서비스가 여행의 질을 한층 높여주었습니다.', '최고경영자모임', '대만', '타이베이', ARRAY(SELECT json_array_elements_text('["최고경영자모임","미식여행","15명여행"]'::json)), '2025-06-24T15:00:00.000Z'::timestamp with time zone, '2025-06-29T15:00:00.000Z'::timestamp with time zone, '5.0', NULL, true, 49, 'published', NULL, 'manual_admin', '2025-06-30T16:30:00.000Z'::timestamp with time zone, NULL, '2025-06-30T16:45:00.000Z'::timestamp with time zone, '2025-06-30T15:00:00.000Z'::timestamp with time zone, '2025-06-30T16:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('76a4c302-943f-4e79-83a2-5b41d3f1a6ae', 'e07b034e-85bc-4dfa-a5fc-385e51aa238d', 'domestic', 'group_corporate', '상인회 제주도 우수 회원 워크숍, 짧지만 강력한 힐링이었습니다', '30명의 상인회 우수 회원들이 제주도의 자연을 즐기며 사업 의지를 다지는 좋은 기회였습니다.', '제주 향토 음식 위주의 식단 구성이 회원들의 입맛을 사로잡았고 식사 장소의 규모도 적절했습니다. 이동 동선이 꼬이지 않게 동부와 서부를 효율적으로 나누어 관광한 점이 만족스러웠습니다. 인솔자가 회원들의 요구사항을 즉각적으로 처리해주는 서비스 정신이 인상적이었습니다.', '상인회', '한국', '제주', ARRAY(SELECT json_array_elements_text('["상인회","워크숍","30명여행"]'::json)), '2025-07-07T15:00:00.000Z'::timestamp with time zone, '2025-07-10T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 34, 'published', NULL, 'manual_admin', '2025-07-11T11:30:00.000Z'::timestamp with time zone, NULL, '2025-07-11T11:45:00.000Z'::timestamp with time zone, '2025-07-11T10:30:00.000Z'::timestamp with time zone, '2025-07-11T11:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('d277148f-48cf-4dfb-bee9-19204e8e0a36', '70a4f86a-7294-47b1-8b68-cb707edb95ca', 'overseas', 'group_small', '대학원 동기들과 떠난 푸켓 휴양 여행, 일정 조율이 매우 자유로웠습니다', '공통 일정은 최소화하고 팀별 자유시간을 극대화하여 모두의 만족도를 높였습니다.', '동기들끼리 조용히 쉬고 싶어 빌라 위주로 숙소를 잡았는데 위치와 서비스 모두 훌륭했습니다. 현지에서 먹고 싶은 메뉴를 즉석에서 반영해주는 가이드의 유연한 서비스에 감동받았습니다. 단체 여행 특유의 압박감 없이 즐긴 진짜 휴가 같은 시간이었습니다.', '대학원모임', '태국', '푸켓', ARRAY(SELECT json_array_elements_text('["대학원모임","휴양여행","일정안정"]'::json)), '2025-07-21T15:00:00.000Z'::timestamp with time zone, '2025-07-26T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 8, 'published', NULL, 'manual_admin', '2025-07-27T15:00:00.000Z'::timestamp with time zone, NULL, '2025-07-27T15:20:00.000Z'::timestamp with time zone, '2025-07-27T14:00:00.000Z'::timestamp with time zone, '2025-07-27T15:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('5dc98900-2c21-480f-a242-2d09f69008ca', 'd1bdfc6a-04ee-4063-8966-de734b1ddfdf', 'domestic', 'group_corporate', '협회 회원 제주 골프 및 휴양 여행, 원활한 진행에 감사드립니다', '30명의 협회원이 함께한 제주 골프 투어는 명문 구장 섭외와 부대 서비스가 매우 훌륭했습니다.', '라운딩 전후의 식사 장소 선정과 메뉴 구성이 남달라 협회원들 사이에서 칭찬이 자자했습니다. 골프를 치지 않는 회원들을 위해 별도의 힐링 코스를 마련해준 유연한 대처가 돋보였습니다. 호텔 객실 배정 시 바다 전망을 최대한 반영해준 세심한 배려에 감동받았습니다.', '협회모임', '한국', '제주', ARRAY(SELECT json_array_elements_text('["협회모임","골프휴양","30명여행"]'::json)), '2025-08-04T15:00:00.000Z'::timestamp with time zone, '2025-08-07T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 44, 'published', NULL, 'manual_admin', '2025-08-08T16:00:00.000Z'::timestamp with time zone, NULL, '2025-08-08T16:15:00.000Z'::timestamp with time zone, '2025-08-08T15:00:00.000Z'::timestamp with time zone, '2025-08-08T16:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('5db3814c-b182-4ca2-8f64-91a6e0c12ac3', 'b3fe9de1-aa59-42c0-afd4-9e0f41543453', 'overseas', 'group_corporate', '협회 이사회 쿠알라룸푸르 워크숍, 집중도 높은 환경이 좋았습니다', '업무 회의와 팀 빌딩 액티비티가 적절히 섞여 협회 운영 방안 논의가 활발히 진행되었습니다.', '조용한 리조트 내 회의실과 장비 지원이 완벽하여 이사회 본연의 업무에 집중할 수 있었습니다. 오후에 진행된 시티 투어와 바투 동굴 방문은 적당한 휴식과 볼거리를 제공했습니다. 현지 음식과 한식을 조화롭게 구성한 식단 덕분에 참석자들의 건강 관리도 수월했습니다.', '협회모임', '말레이시아', '쿠알라룸푸르', ARRAY(SELECT json_array_elements_text('["협회모임","워크숍","일정관리"]'::json)), '2025-08-18T15:00:00.000Z'::timestamp with time zone, '2025-08-24T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 16, 'published', NULL, 'manual_admin', '2025-08-25T14:00:00.000Z'::timestamp with time zone, NULL, '2025-08-25T14:15:00.000Z'::timestamp with time zone, '2025-08-25T13:00:00.000Z'::timestamp with time zone, '2025-08-25T14:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('4a88c90b-bef0-45e7-bb48-a97c1aaf1cd5', 'cfea103c-e616-4d50-809b-2b284277a874', 'overseas', 'parents', '시니어 모임으로 다녀온 후쿠오카 온천 여행, 부모님들도 만족하셨습니다', '이동 거리를 최소화한 동선과 온천 중심의 일정이 어르신들께 딱 맞았습니다.', '어르신들이 걷기에 무리가 없도록 관광지 바로 앞까지 차량이 진입하는 점이 매우 편리했습니다. 식사마다 자극적이지 않고 건강한 현지식으로 구성되어 모든 회원분이 식사를 즐기셨습니다. 가이드의 세심한 보살핌 덕분에 안전 사고 없이 기분 좋게 다녀왔습니다.', '시니어모임', '일본', '후쿠오카', ARRAY(SELECT json_array_elements_text('["시니어모임","힐링여행","온천여행"]'::json)), '2025-09-01T15:00:00.000Z'::timestamp with time zone, '2025-09-06T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 6, 'published', NULL, 'manual_admin', '2025-09-07T10:30:00.000Z'::timestamp with time zone, NULL, '2025-09-07T10:45:00.000Z'::timestamp with time zone, '2025-09-07T09:00:00.000Z'::timestamp with time zone, '2025-09-07T10:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('36592a2e-b8d6-4526-b799-f71b4f1b4ad4', '321c9e9a-a581-45f0-a4d3-b1d749042573', 'domestic', 'group_small', '소규모 단체 부산 요트 및 미식 여행, 알찬 2박 3일이었습니다', '친목 모임 15명이 즐기기에 부족함 없는 숙소와 화려한 야경 투어가 인상적이었습니다.', '해운대 요트 투어 시 우리 팀만을 위한 단독 대절 서비스를 제공받아 매우 특별한 기분이었습니다. 부산의 대표적인 맛집들을 줄 서지 않고 바로 입장할 수 있도록 사전에 조율해주어 시간을 아낄 수 있었습니다. 가이드의 친절한 설명과 사진 촬영 서비스 덕분에 멋진 추억을 많이 남겼습니다.', '소규모단체', '한국', '부산', ARRAY(SELECT json_array_elements_text('["소규모단체","미식여행","15명여행"]'::json)), '2025-09-17T15:00:00.000Z'::timestamp with time zone, '2025-09-20T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 28, 'published', NULL, 'manual_admin', '2025-09-21T16:30:00.000Z'::timestamp with time zone, NULL, '2025-09-21T16:45:00.000Z'::timestamp with time zone, '2025-09-21T15:00:00.000Z'::timestamp with time zone, '2025-09-21T16:30:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('0b3247b7-ab0d-4eb7-acc5-4009f7e89b56', 'a97dce82-fc5a-4d19-9f4d-f8c9a2779ab3', 'overseas', 'group_corporate', '상인회 싱가포르 선진 유통망 견학, 많은 것을 배웠습니다', '싱가포르의 효율적인 물류 시스템과 유통 구조를 직접 확인하며 많은 통찰을 얻은 기회였습니다.', '전문적인 견학 일정 외에도 유니버설 스튜디오 방문 등 재미있는 코스가 섞여 있어 연수의 질이 높았습니다. 도심 내 이동 시 소요 시간을 정확히 예측하여 일정에 차질이 없도록 관리해준 점이 훌륭했습니다. 숙소 컨디션과 주변 인프라가 좋아 저녁 시간의 개별 활동도 매우 즐거웠습니다.', '상인회', '싱가포르', '싱가포르', ARRAY(SELECT json_array_elements_text('["상인회","유통견학","25명여행"]'::json)), '2025-09-19T15:00:00.000Z'::timestamp with time zone, '2025-09-26T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 42, 'published', NULL, 'manual_admin', '2025-09-27T13:00:00.000Z'::timestamp with time zone, NULL, '2025-09-27T13:15:00.000Z'::timestamp with time zone, '2025-09-27T12:00:00.000Z'::timestamp with time zone, '2025-09-27T13:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('29fb2de8-b13b-4a7d-9519-a234f51f719e', '4095fc51-a1da-4684-b047-dba061e0fd74', 'overseas', 'group_corporate', '사업자 모임 말레이시아 코타키나발루 휴양, 재충전의 시간이었습니다', '사업에 지친 회원들이 아름다운 자연 속에서 휴식하며 친목을 다지는 유익한 일정이었습니다.', '석양 투어와 반딧불 투어 등 힐링 코스가 잘 짜여 있어 참여한 회원들의 스트레스 해소에 큰 도움이 되었습니다. 리조트 내 수영장과 부대시설 이용 시간이 넉넉하여 단체 여행임에도 불구하고 개인적인 휴식을 취하기 좋았습니다. 가이드가 회원 개개인의 컨디션을 수시로 체크해주는 세심함이 돋보였습니다.', '사업자모임', '말레이시아', '코타키나발루', ARRAY(SELECT json_array_elements_text('["사업자모임","힐링여행","재충전"]'::json)), '2025-10-11T15:00:00.000Z'::timestamp with time zone, '2025-10-16T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 30, 'published', NULL, 'manual_admin', '2025-10-17T14:00:00.000Z'::timestamp with time zone, NULL, '2025-10-17T14:20:00.000Z'::timestamp with time zone, '2025-10-17T13:00:00.000Z'::timestamp with time zone, '2025-10-17T14:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('53fd3b2d-abda-4790-a15c-f3f9a8d0ae0f', '2b3a476b-4d0a-4b55-8f33-e483710664de', 'domestic', 'group_friends', '동문회 부산 1박 2일 나들이, 30명 대인원 관리가 매끄러웠습니다', '부산의 복잡한 교통 상황에서도 전용 대형 버스 덕분에 쾌적하게 이동했습니다.', '해운대 바다가 한눈에 보이는 숙소와 부산 명물 횟집에서의 저녁 식사가 훌륭했습니다. 30명의 동문이 동시에 움직였지만 집결 시간과 장소가 명확히 안내되어 혼선이 없었습니다. 야간 요트 투어는 이번 여행의 백미로 모두에게 잊지 못할 추억이 되었습니다.', '동문회', '한국', '부산', ARRAY(SELECT json_array_elements_text('["동문회","친목여행","30명여행"]'::json)), '2025-10-24T15:00:00.000Z'::timestamp with time zone, '2025-10-26T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 13, 'published', NULL, 'manual_admin', '2025-10-27T12:00:00.000Z'::timestamp with time zone, NULL, '2025-10-27T12:15:00.000Z'::timestamp with time zone, '2025-10-27T11:00:00.000Z'::timestamp with time zone, '2025-10-27T12:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('20576d4d-2d60-496a-80cd-5c6112b057f0', '0ace0848-2db6-4ef7-b292-a538882eea91', 'overseas', 'group_corporate', '최고경영자 모임 이탈리아 피렌체 와인 투어, 대표님들의 찬사를 받았습니다', '토스카나의 아름다운 풍경과 명품 와이너리 방문이 조화로운 명품 일정이었습니다.', '대표님들이 좋아하시는 프라이빗 와이너리 투어는 예약 과정부터 현지 통역까지 완벽하게 준비되었습니다. 숙소로 사용한 고성 호텔은 역사와 현대적 시설이 잘 어우러져 숙박 자체만으로도 훌륭한 경험이었습니다. 전 일정 동안 비즈니스 클래스급 차량을 제공해주어 이동 중에도 편안한 휴식이 가능했습니다.', '최고경영자모임', '이탈리아', '피렌체', ARRAY(SELECT json_array_elements_text('["최고경영자모임","와인투어","품격여행"]'::json)), '2025-10-17T15:00:00.000Z'::timestamp with time zone, '2025-10-27T15:00:00.000Z'::timestamp with time zone, '5.0', NULL, true, 39, 'published', NULL, 'manual_admin', '2025-10-28T17:00:00.000Z'::timestamp with time zone, NULL, '2025-10-28T17:30:00.000Z'::timestamp with time zone, '2025-10-28T16:00:00.000Z'::timestamp with time zone, '2025-10-28T17:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('ae2dcf67-6653-4970-af79-a7e9fc7a114f', '218764b8-9de0-43fc-901d-b8984e8a9730', 'domestic', 'parents', '시니어 동창회 강릉 여행, 무리 없는 동선과 맛깔나는 한식이 좋았습니다', '어르신들의 체력을 배려한 여유로운 커피 거리 산책과 정갈한 한정식이 인상적이었습니다.', '오랜만에 만난 동창들과 바다를 보며 담소를 나누기에 충분한 시간이 주어져 만족스러웠습니다. 이동 중간에 들른 지역 시장 투어도 인솔자의 안내 덕분에 안전하고 즐겁게 구경했습니다. 숙소가 깨끗하고 접근성이 좋아 어르신들이 이동하기에 매우 편리했습니다.', '시니어모임', '한국', '강릉', ARRAY(SELECT json_array_elements_text('["시니어모임","힐링여행","식사만족"]'::json)), '2025-11-02T15:00:00.000Z'::timestamp with time zone, '2025-11-04T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 14, 'published', NULL, 'manual_admin', '2025-11-05T16:00:00.000Z'::timestamp with time zone, NULL, '2025-11-05T16:15:00.000Z'::timestamp with time zone, '2025-11-05T15:00:00.000Z'::timestamp with time zone, '2025-11-05T16:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('e3ed5dbf-b92c-4b73-9a8e-e60ff72c14e7', 'ed195f22-e488-4488-9f2a-3620c759392f', 'overseas', 'group_corporate', '협회 회원 방콕 미식 및 문화 탐방, 다채로운 즐거움이 있었습니다', '40명의 협회원이 함께한 이번 여행은 방콕의 화려한 사원과 맛있는 길거리 음식까지 두루 경험했습니다.', '대규모 인원이 움직임에도 불구하고 식당 입장과 관람 예약이 미리 완료되어 대기 없이 진행되었습니다. 가이드가 추천해준 고급 태국 요리 전문점은 분위기가 매우 훌륭하여 회원들의 만족도가 상당했습니다. 일정 중 마련된 자유 쇼핑 시간은 회원들의 개별 니즈를 충족시키기에 충분했습니다.', '협회모임', '태국', '방콕', ARRAY(SELECT json_array_elements_text('["협회모임","미식투어","40명여행"]'::json)), '2025-11-11T15:00:00.000Z'::timestamp with time zone, '2025-11-17T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 36, 'published', NULL, 'manual_admin', '2025-11-18T14:00:00.000Z'::timestamp with time zone, NULL, '2025-11-18T14:20:00.000Z'::timestamp with time zone, '2025-11-18T13:00:00.000Z'::timestamp with time zone, '2025-11-18T14:00:00.000Z'::timestamp with time zone);
