INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('6d5c6362-6847-4af5-918b-ea6b8216e231', '1d40c319-8309-421c-9c10-a32e969801ef', 'domestic', 'hiking', '산악회 회원들과 함께한 제주 한라산 원정, 완벽한 서포트였습니다', '등반 허가부터 하산 지점 차량 대기까지 산악회 회원들의 편의를 최우선으로 고려했습니다.', '한라산의 기상 변화에 맞춰 일정을 유연하게 변경해주어 모두가 안전하게 산행을 마칠 수 있었습니다. 하산 후 들른 흑돼지 전문 식당은 넓은 좌석과 맛있는 고기로 회원들의 평이 아주 좋았습니다. 숙소의 위치가 산행 전후 이동하기에 매우 최적화되어 있어 피로도가 낮았습니다.', '산악회', '한국', '제주', ARRAY(SELECT json_array_elements_text('["산악회","산행여행","40명여행"]'::json)), '2026-01-04T15:00:00.000Z'::timestamp with time zone, '2026-01-07T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 31, 'published', NULL, 'manual_admin', '2026-01-08T17:00:00.000Z'::timestamp with time zone, NULL, '2026-01-08T17:15:00.000Z'::timestamp with time zone, '2026-01-08T16:00:00.000Z'::timestamp with time zone, '2026-01-08T17:00:00.000Z'::timestamp with time zone);
