INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('8006288a-523c-4701-b449-fd4dd48878ec', '3d125518-80da-43f3-825c-35407bb43986', 'overseas', 'hiking', '산악회 회원들과 함께한 뉴질랜드 퀸스타운, 대자연의 감동을 느꼈습니다', '하이킹 코스 선정부터 도시락 하나까지 등산 동호인의 니즈를 정확히 파악했습니다.', '퀸스타운의 절경을 배경으로 한 하이킹 코스는 난이도가 적절하여 회원들이 매우 즐거워했습니다. 전용 차량 내부에 등산 스틱과 여분의 생수를 상시 비치해두는 세심함에 감탄했습니다. 일정 중 진행된 양떼 목장 방문과 번지점프 관람도 신선한 재미를 주었습니다.', '산악회', '뉴질랜드', '퀸스타운', ARRAY(SELECT json_array_elements_text('["산악회","자연경관","30명여행"]'::json)), '2026-02-14T15:00:00.000Z'::timestamp with time zone, '2026-02-21T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, true, 11, 'published', NULL, 'manual_admin', '2026-02-22T15:00:00.000Z'::timestamp with time zone, NULL, '2026-02-22T15:15:00.000Z'::timestamp with time zone, '2026-02-22T14:00:00.000Z'::timestamp with time zone, '2026-02-22T15:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('f12cb767-42ae-4737-84d3-7c334187e701', '34cc3831-0c9d-4726-af8c-0a58f68e4c01', 'overseas', 'hiking', '산악회 뉴질랜드 트레킹 원정, 대자연과 함께한 도전적인 시간이었습니다', '뉴질랜드의 험난하면서도 아름다운 코스를 산악회 회원 30명이 안전하게 완주했습니다.', '현지 등반 가이드와 한국어 가이드가 협업하여 회원들의 안전과 편의를 이중으로 체크해주어 안심이 되었습니다. 산행 후 리조트에서 즐긴 바비큐 파티는 회원들 간의 끈끈한 유대감을 느끼기에 충분했습니다. 고난도 코스와 휴식 코스를 적절히 배분하여 체력 관리가 수월했던 점이 좋았습니다.', '산악회', '뉴질랜드', '퀸스타운', ARRAY(SELECT json_array_elements_text('["산악회","트레킹","30명여행"]'::json)), '2026-02-24T15:00:00.000Z'::timestamp with time zone, '2026-03-04T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 40, 'published', NULL, 'manual_admin', '2026-03-05T10:00:00.000Z'::timestamp with time zone, NULL, '2026-03-05T10:15:00.000Z'::timestamp with time zone, '2026-03-05T09:00:00.000Z'::timestamp with time zone, '2026-03-05T10:00:00.000Z'::timestamp with time zone);
