INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('fbfe940a-8de6-496a-a82b-51d3431694d4', 'e041a6e7-9a38-4613-9725-f5500cbd1cb9', 'overseas', 'group_corporate', '사업자 모임 오사카 경제 탐방, 현지 트렌드를 제대로 읽었습니다', '오사카의 주요 상권을 30명의 사업자가 함께 둘러보며 인사이트를 나눈 알찬 일정이었습니다.', '복잡한 상권 내에서도 인원 관리가 철저하여 한 명도 이탈 없이 안전하게 시찰을 마쳤습니다. 인솔자가 현지 사업자들과의 네트워킹 시간을 주선해주어 예상치 못한 비즈니스 기회를 얻기도 했습니다. 숙소 인근에 맛집들이 많아 저녁 자유 시간에도 풍성한 미식을 즐길 수 있었습니다.', '사업자모임', '일본', '오사카', ARRAY(SELECT json_array_elements_text('["사업자모임","경제탐방","30명여행"]'::json)), '2026-10-14T15:00:00.000Z'::timestamp with time zone, '2026-10-19T15:00:00.000Z'::timestamp with time zone, '4.8', NULL, false, 46, 'published', NULL, 'manual_admin', '2026-10-20T14:00:00.000Z'::timestamp with time zone, NULL, '2026-10-20T14:15:00.000Z'::timestamp with time zone, '2026-10-20T13:00:00.000Z'::timestamp with time zone, '2026-10-20T14:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('a04bedd9-b28d-4a47-8871-eea31fab2e90', '13a44408-171a-443a-8a56-7ca8c702a6c8', 'overseas', 'parents', '시니어 모임 싱가포르 시티 투어, 안전하고 편안한 이동에 만족했습니다', '연령대가 높은 시니어 회원들을 위한 무리 없는 도보 동선과 쾌적한 전용 차량이 돋보였습니다.', '가든스 바이 더 베이와 마리나 베이 샌즈 등 핵심 관광지를 지치지 않고 즐길 수 있도록 배려한 일정이 좋았습니다. 식사 때마다 한국인 입맛에 맞는 현지 식당을 엄선해주어 회원들이 매우 기뻐하셨습니다. 저녁 야경 투어 시에도 인원 관리가 철저하여 마음 놓고 관광을 즐길 수 있었습니다.', '시니어모임', '싱가포르', '싱가포르', ARRAY(SELECT json_array_elements_text('["시니어모임","시티투어","동선안정"]'::json)), '2026-11-04T15:00:00.000Z'::timestamp with time zone, '2026-11-09T15:00:00.000Z'::timestamp with time zone, '4.7', NULL, false, 29, 'published', NULL, 'manual_admin', '2026-11-10T11:00:00.000Z'::timestamp with time zone, NULL, '2026-11-10T11:15:00.000Z'::timestamp with time zone, '2026-11-10T10:00:00.000Z'::timestamp with time zone, '2026-11-10T11:00:00.000Z'::timestamp with time zone);
INSERT INTO travel_reviews ("id", "user_id", "category", "review_type", "title", "excerpt", "body", "customer_type", "destination_country", "destination_city", "tags", "travel_month", "displayed_date", "rating_label", "thumbnail_url", "is_featured", "display_order", "status", "rejection_reason", "source_type", "approved_at", "approved_by", "published_at", "created_at", "updated_at") VALUES ('6c613745-864f-4149-b454-48b8e677d626', '3236dd0c-4e1c-412f-aa5a-8c738195e3a0', 'domestic', 'group_small', '소규모 모임 강릉 경포대 우정 여행, 1박 2일의 행복이었습니다', '친구 10명이 함께한 이번 여행은 탁 트인 바다 뷰 숙소와 신선한 회 한 상이 백미였습니다.', '단체 여행이라기보다 친구들끼리 오붓하게 여행하는 느낌을 살려주면서도 중요한 예약은 다 되어 있어 편리했습니다. 가이드가 추천해준 해안가 카페는 분위기가 너무 좋아 다들 사진 찍느라 정신이 없었습니다. 다음 모임 여행도 이곳을 통해 진행하고 싶을 정도로 만족스러운 운영이었습니다.', '소규모단체', '한국', '강릉', ARRAY(SELECT json_array_elements_text('["소규모단체","우정여행","10명여행"]'::json)), '2026-11-17T15:00:00.000Z'::timestamp with time zone, '2026-11-19T15:00:00.000Z'::timestamp with time zone, '4.9', NULL, false, 48, 'published', NULL, 'manual_admin', '2026-11-20T09:00:00.000Z'::timestamp with time zone, NULL, '2026-11-20T09:10:00.000Z'::timestamp with time zone, '2026-11-20T08:30:00.000Z'::timestamp with time zone, '2026-11-20T09:00:00.000Z'::timestamp with time zone);
